import{_ as n,M as d,p as l,q as t,R as i,t as e,N as r,a1 as s}from"./framework-e0dd9823.js";const o={},c=s(`<h1 id="css-元素定位" tabindex="-1"><a class="header-anchor" href="#css-元素定位" aria-hidden="true">#</a> CSS 元素定位</h1><p><em>定位指的是更改元素的默认排列方式</em></p><h4 id="_1-普通流定位-文档流定位" tabindex="-1"><a class="header-anchor" href="#_1-普通流定位-文档流定位" aria-hidden="true">#</a> 1. 普通流定位(文档流定位)</h4><p>默认模式排列，块级元素从上到下，行级元素从左到右</p><h4 id="_2-浮动定位" tabindex="-1"><a class="header-anchor" href="#_2-浮动定位" aria-hidden="true">#</a> 2. 浮动定位</h4><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>float:left/right/none;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>特点：</li></ul><p>浮动元素脱离文档流，不在占据空间。如果一行显示不下，会自动换行（可能被卡主），添加了浮动的元素会变成块级元素（也符合行内块的特点），并且也可以设置 margin 属性。</p><ul><li>影响：</li></ul><ol><li>元素浮动会由于脱离了自身的文档流，影响后续元素布局</li><li>添加了浮动的元素会影响父元素的高度</li></ol><ul><li>解决方案：</li></ul><ol><li>清除自身元素前面的浮动</li><li>给父元素设置高度，但是大部分情况下高度不固定（不推荐）</li><li>给父元素加浮动，但同时也会影响父元素的后续元素（不推荐）</li><li>在父元素的最后添加一个空标签（必须为块级元素），并且设置属性<code>clear:both；</code>但如果页面空标签多了，会影响性能</li><li>给父元素设置<code>overflow:hidden/auto;</code></li><li>给父元素设置如下属性（推荐使用）</li></ol><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>:after {
content:&quot;&quot;;
display:block;
clear:both;
height:0;
line-height:0;
visibility:hidden;
}
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="_3-相对定位" tabindex="-1"><a class="header-anchor" href="#_3-相对定位" aria-hidden="true">#</a> 3. 相对定位</h4><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>position:relative;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>保留自身空间（脱离文档流），相对于原来位置定位。并配合偏移属性 left/right/top/bottom 一起使用。</p><h4 id="_4-绝对定位" tabindex="-1"><a class="header-anchor" href="#_4-绝对定位" aria-hidden="true">#</a> 4. 绝对定位</h4><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>position:absolute;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>不保留自身空间，相对于离自身最近的已定位的祖先元素进行定位，如果找不到，就相对 body 进行定位。并配合偏移属性 left/right/top/bottom 一起使用。</p><h4 id="_5-固定定位" tabindex="-1"><a class="header-anchor" href="#_5-固定定位" aria-hidden="true">#</a> 5. 固定定位</h4><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>position:fixed;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>永远相对于浏览器页面进行定位，并配合偏移属性 left/right/top/bottom 一起使用。</p><h4 id="_6-弹性布局定位" tabindex="-1"><a class="header-anchor" href="#_6-弹性布局定位" aria-hidden="true">#</a> 6.弹性布局定位</h4><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>display:flex;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,24),h={href:"https://www.runoob.com/w3cnote/flex-grammar.html",target:"_blank",rel:"noopener noreferrer"};function u(v,m){const a=d("ExternalLinkIcon");return l(),t("div",null,[c,i("p",null,[e("弹性定位是一种新的定位方式，他自身具有一些计算能力，可以减少在布局时的很多计算问题，本文不多做介绍。详情语法"),i("a",h,[e("点击"),r(a)]),e("这里")])])}const p=n(o,[["render",u],["__file","CSS-position.html.vue"]]);export{p as default};
